mapper.select:
select date_format(po.updated_at, '%Y-%m-%d') as date,
       coalesce(sum(po.amount), 0) as revenue
from product_orders po
where po.status = 'PAID'
  and po.updated_at >= #{startTime}
  and po.updated_at < #{endTime}
  and po.shop_id in

    #{shopId}

group by date_format(po.updated_at, '%Y-%m-%d')
order by date_format(po.updated_at, '%Y-%m-%d') asc

select po.product_id as productId,
       coalesce(sp.name, concat('商品#', po.product_id)) as productName,
       count(1) as orderCount
from product_orders po
         left join shop_products sp on sp.id = po.product_id
where po.status = 'PAID'
  and po.updated_at >= #{startTime}
  and po.updated_at < #{endTime}
  and po.shop_id in

    #{shopId}

group by po.product_id, sp.name
order by orderCount desc, po.product_id desc
limit #{limit}
